"use client";

import React, { useState } from "react";

interface FormData {
    email: string;
    password: string;
    mfaCode: string;
}

export default function LoginPage() {
    const [formData, setFormData] = useState<FormData>({ email: "", password: "", mfaCode: "" });
    const [error, setError] = useState<string>("");
    const [loading, setLoading] = useState<boolean>(false);
    const [requiresMFA, setRequiresMFA] = useState<boolean>(false);

    const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setError("");
        setLoading(true);
        // Simulate login
        setTimeout(() => {
            setError("Invalid credentials. Please try again.");
            setLoading(false);
        }, 1500);
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    return (
        <div style={{
        minHeight: "100vh",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            background: "linear-gradient(135deg, #eff6ff 0%, #e0e7ff 100%)",
            padding: "0 16px",
            fontFamily: "'Segoe UI', system-ui, -apple-system, sans-serif",
    }}>
    <div style={{ maxWidth: 448, width: "100%" }}>

    {/* Header */}
    <div style={{ textAlign: "center", marginBottom: 32 }}>
    <div style={{
        margin: "0 auto 16px",
            height: 64, width: 64,
            background: "#2563eb",
            borderRadius: 12,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
    }}>
    <svg style={{ height: 40, width: 40 }} fill="none" stroke="white" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
    d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z" />
        </svg>
        </div>
        <h2 style={{ fontSize: 30, fontWeight: 700, color: "#111827", margin: "0 0 8px" }}>
    Card Cove Admin
    </h2>
    <p style={{ fontSize: 14, color: "#6b7280", margin: 0 }}>
    {requiresMFA ? "Enter your MFA code to continue" : "Sign in to access the admin portal"}
    </p>
    </div>

    {/* Card */}
    <div style={{
        background: "#fff",
            borderRadius: 12,
            boxShadow: "0 20px 25px -5px rgba(0,0,0,0.1), 0 10px 10px -5px rgba(0,0,0,0.04)",
            padding: 32,
    }}>
    <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: 24 }}>

    {/* Error */}
    {error && (
        <div style={{
        background: "#fef2f2",
            border: "1px solid #fecaca",
            borderRadius: 8,
            padding: 16,
            display: "flex",
            alignItems: "flex-start",
            gap: 12,
    }}>
        <svg style={{ height: 20, width: 20, flexShrink: 0 }} fill="none" stroke="#f87171" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
        d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            <p style={{ fontSize: 14, color: "#b91c1c", margin: 0 }}>{error}</p>
    </div>
    )}

    {!requiresMFA ? (
        <>
            {/* Email */}
        <div>
        <label htmlFor="email" style={{ display: "block", fontSize: 14, fontWeight: 500, color: "#374151", marginBottom: 8 }}>
        Email Address
    </label>
    <input
        id="email" name="email" type="email" autoComplete="email" required
        value={formData.email} onChange={handleChange}
        placeholder="admin@cardcove.com"
        style={{
        width: "100%", padding: "12px 16px", border: "1px solid #d1d5db",
            borderRadius: 8, fontSize: 14, color: "#111827", background: "#fff",
            outline: "none", boxSizing: "border-box", transition: "border-color 0.2s",
    }}
        onFocus={(e: React.FocusEvent<HTMLInputElement>) => e.target.style.borderColor = "#3b82f6"}
        onBlur={(e: React.FocusEvent<HTMLInputElement>) => e.target.style.borderColor = "#d1d5db"}
        />
        </div>

        {/* Password */}
        <div>
            <label htmlFor="password" style={{ display: "block", fontSize: 14, fontWeight: 500, color: "#374151", marginBottom: 8 }}>
        Password
        </label>
        <input
        id="password" name="password" type="password" autoComplete="current-password" required
        value={formData.password} onChange={handleChange}
        placeholder="••••••••"
        style={{
        width: "100%", padding: "12px 16px", border: "1px solid #d1d5db",
            borderRadius: 8, fontSize: 14, color: "#111827", background: "#fff",
            outline: "none", boxSizing: "border-box", transition: "border-color 0.2s",
    }}
        onFocus={(e: React.FocusEvent<HTMLInputElement>) => e.target.style.borderColor = "#3b82f6"}
        onBlur={(e: React.FocusEvent<HTMLInputElement>) => e.target.style.borderColor = "#d1d5db"}
        />
        </div>
        </>
    ) : (
        <>
            {/* MFA */}
        <div>
        <label htmlFor="mfaCode" style={{ display: "block", fontSize: 14, fontWeight: 500, color: "#374151", marginBottom: 8 }}>
        MFA Code
    </label>
    <input
        id="mfaCode" name="mfaCode" type="text" maxLength={6} required
        value={formData.mfaCode} onChange={handleChange}
        placeholder="123456" autoFocus
        style={{
        width: "100%", padding: "12px 16px", border: "1px solid #d1d5db",
            borderRadius: 8, fontSize: 24, color: "#111827", background: "#fff",
            outline: "none", boxSizing: "border-box", textAlign: "center",
            letterSpacing: "0.3em", transition: "border-color 0.2s",
    }}
        onFocus={(e: React.FocusEvent<HTMLInputElement>) => e.target.style.borderColor = "#3b82f6"}
        onBlur={(e: React.FocusEvent<HTMLInputElement>) => e.target.style.borderColor = "#d1d5db"}
        />
        <p style={{ marginTop: 8, fontSize: 12, color: "#6b7280", textAlign: "center" }}>
        Enter the 6-digit code from your authenticator app
    </p>
    </div>
    <button
        type="button"
        onClick={() => { setRequiresMFA(false); setFormData({ ...formData, mfaCode: "" }); }}
        style={{
        background: "none", border: "none", cursor: "pointer",
            fontSize: 14, color: "#6b7280", padding: 0,
    }}
    >
    ← Back to login
    </button>
    </>
    )}

    {/* Remember me / Forgot password */}
    {!requiresMFA && (
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <label style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer" }}>
        <input type="checkbox" style={{ height: 16, width: 16, accentColor: "#2563eb" }} />
    <span style={{ fontSize: 14, color: "#374151" }}>Remember me</span>
    </label>
    <a href="/forgot-password" style={{ fontSize: 14, fontWeight: 500, color: "#2563eb", textDecoration: "none" }}>
        Forgot password?
        </a>
        </div>
    )}

    {/* Submit Button */}
    <button
        type="submit"
    disabled={loading}
    style={{
        width: "100%", display: "flex", justifyContent: "center", alignItems: "center",
            padding: "12px 16px", border: "none", borderRadius: 8,
            fontSize: 14, fontWeight: 500, color: "#fff",
            background: loading ? "#93c5fd" : "#2563eb",
            cursor: loading ? "not-allowed" : "pointer",
            transition: "background 0.2s",
    }}
    onMouseOver={(e: React.MouseEvent<HTMLButtonElement>) => { if (!loading) (e.target as HTMLButtonElement).style.background = "#1d4ed8"; }}
    onMouseOut={(e: React.MouseEvent<HTMLButtonElement>) => { if (!loading) (e.target as HTMLButtonElement).style.background = "#2563eb"; }}
>
    {loading ? (
        <svg style={{ animation: "spin 1s linear infinite", height: 20, width: 20 }} fill="none" viewBox="0 0 24 24">
        <style>{`@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }`}</style>
    <circle style={{ opacity: 0.25 }} cx="12" cy="12" r="10" stroke="white" strokeWidth="4" />
    <path style={{ opacity: 0.75 }} fill="white"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
            </svg>
    ) : requiresMFA ? "Verify & Sign In" : "Sign In"}
    </button>
    </form>

    {/* Demo Credentials */}
    <div style={{ marginTop: 24, padding: 16, background: "#f9fafb", borderRadius: 8 }}>
    <p style={{ fontSize: 12, color: "#6b7280", textAlign: "center", marginBottom: 8 }}>Demo Credentials:</p>
    <div style={{ fontSize: 12, color: "#374151", display: "flex", flexDirection: "column", gap: 4 }}>
    <p style={{ margin: 0 }}><strong>Email:</strong> admin@cardcove.com</p>
    <p style={{ margin: 0 }}><strong>Password:</strong> Admin@123</p>
    </div>
    </div>
    </div>

    {/* Footer */}
    <p style={{ textAlign: "center", fontSize: 12, color: "#9ca3af", marginTop: 24 }}>
© 2024 Card Cove. All rights reserved.
    </p>
    </div>
    </div>
);
}
